//! Substrate bridge: threads the universal Fano/Triton substrate into
//! monster/polyglot.
//!
//! Integration points:
//!
//! 1. **FOIL admission gate** -- TritonAdmissionPhase maps to Verdict sign
//!    (ForkFuture=+1 accept, RaceFoldPresent=0 abstain, VentInterferePast=-1
//!    decline). The god formula weight serves as the admission score.
//!
//! 2. **Protocol69** -- broadcast(66) XOR local(7) = 69. The low-bit
//!    projection maps through triton_collide(66%8, 7) on the Fano plane:
//!    2 ^ 7 = 5, a visible Fano point.
//!
//! 3. **AOT cache** -- cache keys use Fano projection for O(1) lookup instead
//!    of linear scan: any u64 hash projects to one of the 8 Fano slots via
//!    masking the low 3 bits.

/// XOR collision on the 3-bit Fano carrier. Identical to
/// `distributed_inference::fano_runtime::triton_collide`.
#[inline(always)]
pub const fn triton_collide(lhs: u8, rhs: u8) -> u8 {
    (lhs ^ rhs) & 0b111
}

/// Project an arbitrary value to a visible Fano point (1..7).
/// Values already in range pass through; 0 (god/root) maps to 1.
#[inline(always)]
pub const fn project_to_fano(value: u8) -> u8 {
    let masked = value & 0b111;
    if masked == 0 {
        1
    } else {
        masked
    }
}

/// The God Formula: `budget - min(rejections, budget) + 1`.
/// Always >= 1. Mirrors `foil_god_weight` in distributed-inference and
/// `FRFProfile.stabilityWeight` in monster-swarm.
/// Uses saturating arithmetic to stay safe at u32::MAX.
#[inline(always)]
pub const fn admission_score(round: u32, rejections: u32) -> u32 {
    let capped = if rejections < round {
        rejections
    } else {
        round
    };
    (round - capped).saturating_add(1)
}

/// Project a source hash to a Fano cache slot (0..7) for O(1) lookup.
/// This replaces linear scan over cache entries: the low 3 bits of any
/// hash are a natural Fano-plane index.
#[inline(always)]
pub const fn fano_cache_key(source_hash: u64) -> u8 {
    (source_hash & 0b111) as u8
}

/// Check that Protocol69 maps to Fano XOR: broadcast(66) XOR local(7) = 69,
/// and triton_collide(66%8, 7%8) yields a visible Fano point (1..7).
///
/// Returns true iff:
///   1. broadcast XOR local == 69 (the protocol identity)
///   2. triton_collide(broadcast%8, local%8) lands on a visible Fano point
///   3. The collision result AND 7 equals a Fano point (nonzero in the carrier)
#[inline(always)]
pub const fn protocol69_is_fano(broadcast: u8, local: u8) -> bool {
    let full_xor = broadcast ^ local;
    if full_xor != 69 {
        return false;
    }
    let lhs_fano = broadcast % 8;
    let rhs_fano = local % 8;
    let collision = triton_collide(lhs_fano, rhs_fano);
    // Collision must be a visible Fano point (1..7), not the god/root (0)
    (collision & 0b111) != 0
}

/// Map a TritonAdmissionPhase name to a Verdict sign.
///
/// - ForkFuture         -> +1 (accept)
/// - RaceFoldPresent    -> 0  (abstain)
/// - VentInterferePast  -> -1 (decline)
///
/// Returns 0 for unknown phases (fail-safe: abstain).
#[inline(always)]
pub fn verdict_from_phase(phase: &str) -> i8 {
    match phase {
        "ForkFuture" | "fork-future" | "future" | "fork" => 1,
        "RaceFoldPresent" | "race-fold-present" | "present" | "race-fold" => 0,
        "VentInterferePast" | "vent-interfere-past" | "past" | "vent" => -1,
        _ => 0,
    }
}

// ─── Lacey64 Anti-Tamper Seal ──────────────────────────────────────

/// Produce one provable byte: (157 * ((seed + 73*k) & 0xFF) + 101) & 0xFF.
/// Lean: ProvableRandomness.lean -- 256-byte cycle is a full permutation.
#[inline(always)]
const fn provable_byte(seed: u64, k: u64) -> u8 {
    let weyl = ((seed.wrapping_add(73u64.wrapping_mul(k))) & 0xFF) as u32;
    ((157u32.wrapping_mul(weyl).wrapping_add(101)) & 0xFF) as u8
}

/// Lacey64 seal: 16 provable bytes from a 64-bit seed, returned as u64
/// (the high 64 bits of the 128-bit Weyl chain). Deterministic, no alloc.
#[inline]
pub const fn lacey64_seal(seed: u64) -> u64 {
    let mut hash: u64 = 0;
    let mut k = 0u64;
    while k < 16 {
        let byte = provable_byte(seed, k) as u64;
        hash = (hash << 4) | (byte & 0xF);
        k += 1;
    }
    hash
}

// ─── Universal Model Execution Admission ──────────────────────────

/// Admit a model execution request into the inference pool.
///
/// Gates:
///   1. God formula weight > threshold (2). The clinamen floor (+1)
///      means weight is always >= 1, so a model needs at least 2
///      rounds of survival beyond rejections to be admitted.
///
/// Returns (admitted, weight, seal).
///   - admitted: true if weight > threshold
///   - weight: god formula score (always >= 1)
///   - seal: Lacey64 fingerprint mixing round, rejections, and model_hash
///     for anti-tamper verification
///
/// Lean: GodFormula.lean (buleyean_positivity), ProvableRandomness.lean
pub fn admit_model_execution(round: u32, rejections: u32, model_hash: u64) -> (bool, u32, u64) {
    let weight = admission_score(round, rejections);

    // Mix round, rejections, and model_hash into a single seed for the seal
    let seed = model_hash
        .wrapping_mul(31)
        .wrapping_add(round as u64)
        .wrapping_mul(31)
        .wrapping_add(rejections as u64);
    let seal = lacey64_seal(seed);

    const THRESHOLD: u32 = 2;
    let admitted = weight > THRESHOLD;

    (admitted, weight, seal)
}

#[cfg(test)]
mod tests {
    use super::*;

    // ---------------------------------------------------------------
    // Protocol69 = Fano XOR
    // ---------------------------------------------------------------

    #[test]
    fn protocol69_is_fano_canonical() {
        // 66 XOR 7 = 69 (the protocol identity)
        assert_eq!(66u8 ^ 7u8, 69);
        // 66%8 = 2, 7%8 = 7
        assert_eq!(66 % 8, 2);
        assert_eq!(7 % 8, 7);
        // triton_collide(2, 7) = (2^7) & 7 = 5
        assert_eq!(triton_collide(2, 7), 5);
        // 5 is a visible Fano point (1..7)
        assert!(protocol69_is_fano(66, 7));
    }

    #[test]
    fn protocol69_rejects_wrong_xor() {
        // 66 XOR 6 = 68, not 69
        assert!(!protocol69_is_fano(66, 6));
        // 65 XOR 7 = 70, not 69
        assert!(!protocol69_is_fano(65, 7));
    }

    #[test]
    fn substrate_triton_collide_matches_fano_runtime() {
        // Self-collision exits to root (god position 0)
        for p in 0..8u8 {
            assert_eq!(triton_collide(p, p), 0);
        }
        // XOR is commutative
        for a in 0..8u8 {
            for b in 0..8u8 {
                assert_eq!(triton_collide(a, b), triton_collide(b, a));
            }
        }
        // All results stay in the 3-bit carrier
        for a in 0..=255u8 {
            for b in 0..=15u8 {
                assert!(triton_collide(a, b) <= 7);
            }
        }
    }

    #[test]
    fn substrate_project_to_fano_yields_visible_points() {
        for v in 0..=255u8 {
            let p = project_to_fano(v);
            assert!(p >= 1 && p <= 7, "project_to_fano({v}) = {p}, not in 1..7");
        }
        // 0 (god/root) maps to 1
        assert_eq!(project_to_fano(0), 1);
        // Already-visible points pass through
        for v in 1..=7u8 {
            assert_eq!(project_to_fano(v), v);
        }
    }

    // ---------------------------------------------------------------
    // God formula always positive
    // ---------------------------------------------------------------

    #[test]
    fn substrate_god_formula_always_positive() {
        // Edge cases
        assert_eq!(admission_score(0, 0), 1);
        assert_eq!(admission_score(0, 100), 1);
        assert_eq!(admission_score(100, 0), 101);
        assert_eq!(admission_score(100, 100), 1);
        assert_eq!(admission_score(100, 50), 51);
        assert_eq!(admission_score(u32::MAX, u32::MAX), 1);
        assert_eq!(admission_score(u32::MAX, 0), u32::MAX); // saturates
                                                            // Brute-force: always >= 1
        for round in 0..256u32 {
            for rej in 0..256u32 {
                let score = admission_score(round, rej);
                assert!(
                    score >= 1,
                    "admission_score({round}, {rej}) = {score}, must be >= 1"
                );
            }
        }
    }

    #[test]
    fn substrate_god_formula_matches_distributed_inference() {
        // The god formula in distributed-inference/gnosis_foil.rs is:
        //   budget.saturating_sub(rejection.min(budget)) + 1
        // Ours is identical for u32 (no overflow concern for sub after min).
        fn reference_god_weight(budget: u32, rejection: u32) -> u32 {
            budget.saturating_sub(rejection.min(budget)) + 1
        }
        for b in 0..512u32 {
            for r in 0..512u32 {
                assert_eq!(
                    admission_score(b, r),
                    reference_god_weight(b, r),
                    "mismatch at budget={b}, rejection={r}"
                );
            }
        }
    }

    // ---------------------------------------------------------------
    // Cache key maps to 0..7
    // ---------------------------------------------------------------

    #[test]
    fn substrate_cache_key_range() {
        let test_hashes: [u64; 8] = [0, 1, 7, 8, 255, u64::MAX, 0xDEADBEEF, 196884];
        for hash in test_hashes {
            let key = fano_cache_key(hash);
            assert!(key <= 7, "fano_cache_key({hash:#x}) = {key}, not in 0..7");
        }
        // All 8 slots reachable
        let mut seen = [false; 8];
        for i in 0..8u64 {
            seen[fano_cache_key(i) as usize] = true;
        }
        assert!(seen.iter().all(|&s| s), "not all 8 Fano slots reachable");
    }

    #[test]
    fn substrate_cache_key_deterministic() {
        for hash in [0u64, 42, 196884, u64::MAX] {
            assert_eq!(fano_cache_key(hash), fano_cache_key(hash));
        }
    }

    // ---------------------------------------------------------------
    // Verdict mapping covers all phases
    // ---------------------------------------------------------------

    #[test]
    fn substrate_verdict_covers_all_phases() {
        // Canonical enum names
        assert_eq!(verdict_from_phase("ForkFuture"), 1);
        assert_eq!(verdict_from_phase("RaceFoldPresent"), 0);
        assert_eq!(verdict_from_phase("VentInterferePast"), -1);

        // Wire names (as used in foil_admission_gate.rs parse_resident_triton_phase)
        assert_eq!(verdict_from_phase("fork-future"), 1);
        assert_eq!(verdict_from_phase("race-fold-present"), 0);
        assert_eq!(verdict_from_phase("vent-interfere-past"), -1);

        // Short aliases
        assert_eq!(verdict_from_phase("future"), 1);
        assert_eq!(verdict_from_phase("fork"), 1);
        assert_eq!(verdict_from_phase("present"), 0);
        assert_eq!(verdict_from_phase("race-fold"), 0);
        assert_eq!(verdict_from_phase("past"), -1);
        assert_eq!(verdict_from_phase("vent"), -1);

        // Unknown -> abstain (fail-safe)
        assert_eq!(verdict_from_phase("unknown"), 0);
        assert_eq!(verdict_from_phase(""), 0);
    }

    #[test]
    fn substrate_verdict_sign_algebra() {
        // +1 * -1 = -1 (accept meeting decline = decline, like interference)
        let accept = verdict_from_phase("ForkFuture");
        let decline = verdict_from_phase("VentInterferePast");
        let abstain = verdict_from_phase("RaceFoldPresent");
        assert_eq!(accept * decline, -1);
        assert_eq!(accept * abstain, 0);
        assert_eq!(decline * abstain, 0);
        assert_eq!(accept * accept, 1);
        assert_eq!(decline * decline, 1);
    }

    // ---------------------------------------------------------------
    // Integration: god formula + Fano projection + verdict compose
    // ---------------------------------------------------------------

    #[test]
    fn substrate_admission_score_projects_to_fano() {
        // The admission score can be projected to a Fano cache key
        for round in [1u32, 5, 12, 100, 196884] {
            for rej in [0u32, 1, round / 2, round] {
                let score = admission_score(round, rej);
                let key = fano_cache_key(score as u64);
                assert!(key <= 7);
                // Score is always positive, so project_to_fano should yield
                // a visible point
                let fano_point = project_to_fano(score as u8);
                assert!(fano_point >= 1 && fano_point <= 7);
            }
        }
    }

    // ---------------------------------------------------------------
    // Model execution admission
    // ---------------------------------------------------------------

    #[test]
    fn admit_model_execution_always_admits_above_threshold() {
        // God formula always >= 1, threshold is 2.
        // Round=0, rej=0 -> weight=1 -> NOT admitted (below threshold)
        let (admitted, weight, _seal) = admit_model_execution(0, 0, 0xDEAD);
        assert!(!admitted);
        assert_eq!(weight, 1);

        // Round=1, rej=0 -> weight=2 -> NOT admitted (not above, equal)
        let (admitted, weight, _seal) = admit_model_execution(1, 0, 0xBEEF);
        assert!(!admitted);
        assert_eq!(weight, 2);

        // Round=2, rej=0 -> weight=3 -> admitted
        let (admitted, weight, _seal) = admit_model_execution(2, 0, 0xCAFE);
        assert!(admitted);
        assert_eq!(weight, 3);
    }

    #[test]
    fn admit_model_execution_seal_deterministic() {
        let (_, _, seal_a) = admit_model_execution(10, 3, 0x196884);
        let (_, _, seal_b) = admit_model_execution(10, 3, 0x196884);
        assert_eq!(seal_a, seal_b);
    }

    #[test]
    fn admit_model_execution_seal_varies_with_hash() {
        let (_, _, seal_a) = admit_model_execution(10, 3, 0xAAAA);
        let (_, _, seal_b) = admit_model_execution(10, 3, 0xBBBB);
        assert_ne!(seal_a, seal_b);
    }

    #[test]
    fn admit_model_execution_high_rejections() {
        // Round=100, rej=99 -> weight=2 -> NOT admitted (equal, not above)
        let (admitted, weight, _) = admit_model_execution(100, 99, 42);
        assert!(!admitted);
        assert_eq!(weight, 2);

        // Round=100, rej=100 -> weight=1 -> NOT admitted
        let (admitted, weight, _) = admit_model_execution(100, 100, 42);
        assert!(!admitted);
        assert_eq!(weight, 1);

        // Round=100, rej=97 -> weight=4 -> admitted
        let (admitted, weight, _) = admit_model_execution(100, 97, 42);
        assert!(admitted);
        assert_eq!(weight, 4);
    }
}
